package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.Reader;
import java.io.StringReader;
import java.util.ArrayList;
import java.util.List;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVParserTest {

    private CSVFormat formatMock;
    private Lexer lexerMock;
    private Reader reader;

    // Subclass CSVParser to inject mocks and control behavior for testing
    private static class TestCSVParser extends CSVParser {
        private final Lexer lexerMock;
        private final List<CSVRecord> recordsToReturn;
        private int callCount = 0;

        TestCSVParser(Reader reader, CSVFormat format, Lexer lexerMock, List<CSVRecord> recordsToReturn) {
            super(reader, format);
            this.lexerMock = lexerMock;
            this.recordsToReturn = recordsToReturn;
        }

        @Override
        public <T extends List<CSVRecord>> T getRecords(T records) throws IOException {
            // Simulate adding records to the passed list
            records.addAll(recordsToReturn);
            return records;
        }
    }

    @BeforeEach
    void setUp() {
        formatMock = mock(CSVFormat.class);
        lexerMock = mock(Lexer.class);
        reader = new StringReader("header1,header2\nvalue1,value2\n");
    }

    @Test
    void testGetRecords_returnsEmptyListWhenNoRecords() throws IOException {
        List<CSVRecord> emptyRecords = new ArrayList<>();
        TestCSVParser parser = new TestCSVParser(reader, formatMock, lexerMock, emptyRecords);

        List<CSVRecord> result = parser.getRecords();

        assertNotNull(result, "Result should not be null");
        assertTrue(result.isEmpty(), "Result list should be empty");
    }

    @Test
    void testGetRecords_returnsListWithRecords() throws IOException {
        CSVRecord record1 = mock(CSVRecord.class);
        CSVRecord record2 = mock(CSVRecord.class);
        List<CSVRecord> mockRecords = new ArrayList<>();
        mockRecords.add(record1);
        mockRecords.add(record2);

        TestCSVParser parser = new TestCSVParser(reader, formatMock, lexerMock, mockRecords);

        List<CSVRecord> result = parser.getRecords();

        assertNotNull(result, "Result should not be null");
        assertEquals(2, result.size(), "Result list size should be 2");
        assertSame(record1, result.get(0), "First record should be record1");
        assertSame(record2, result.get(1), "Second record should be record2");
    }

    @Test
    void testGetRecords_throwsIOException() throws IOException {
        CSVParser parser = new CSVParser(reader, formatMock) {
            @Override
            public <T extends List<CSVRecord>> T getRecords(T records) throws IOException {
                throw new IOException("Simulated IO Exception");
            }
        };

        IOException thrown = assertThrows(IOException.class, parser::getRecords);
        assertEquals("Simulated IO Exception", thrown.getMessage());
    }
}
